import React from 'react';
import { render, fireEvent, waitFor } from '@testing-library/react-native';
import { Linking } from 'react-native';
import PointsDetailView from '../../../src/screens/PointsDetail/view';
import { PointsDetailProps } from '../../../src/screens/PointsDetail/Models';
import { TestProvider } from '../../__mocks__/utils/test-provider';
import '@testing-library/jest-native/extend-expect';

jest.mock('react-native', () => {
  const RN = jest.requireActual('react-native');
  return {
    ...RN,
    Linking: {
      ...RN.Linking,
      openURL: jest.fn(),
    },
    Dimensions: {
      get: jest.fn(() => ({ height: 800, width: 400 })),
    },
  };
});

jest.mock('~/constants/functions', () => ({
  eventModalView: jest.fn(),
  eventSelectContent: jest.fn(),
}));

jest.mock('../../../src/services/moment', () => ({
  moment: jest.fn((date: string) => {
    const mockMoment = {
      format: jest.fn((format: string) => {
        if (format === 'DD') return '15';
        if (format === 'MMM') return 'Jan';
        if (format === 'YYYY') return '2024';
        if (format === 'HH:mm') return '10:30';
        return date;
      }),
    };
    return mockMoment;
  }),
}));

jest.mock('../../../src/utils/functions', () => ({
  formatToCurrency: jest.fn((value: number) => `R$ ${value.toFixed(2).replace('.', ',')}`),
}));

const mockModalizeRef = {
  open: jest.fn(),
  close: jest.fn(),
};

jest.mock('react', () => {
  const React = jest.requireActual('react');
  return {
    ...React,
    useRef: jest.fn(() => ({ current: mockModalizeRef })),
  };
});

describe('PointsDetailView', () => {
  const mockHandleGoBack = jest.fn();
