      provider: 'test-provider',
      extraInfo: 'test info',
      fields: [
        { label: 'Marca', value: 'Toyota' },
        { label: 'Modelo', value: 'Corolla' },
        { label: 'Placa', value: 'ABC-1234' },
      ],
    },
  };

  const mockPointsAvailable = 5000;

  beforeEach(() => {
    jest.clearAllMocks();
  });

  it('should render component with transaction data', () => {
    const { getByText } = render(
      <TestProvider>
        <PointsDetailView
          handleGoBack={mockHandleGoBack}
          transaction={mockTransaction}
          pointsAvailable={mockPointsAvailable}
        />
      </TestProvider>
    );

    expect(getByText('Test Transaction')).toBeTruthy();
    expect(getByText(/\+ 1\.000/)).toBeTruthy();
  });

